INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-64311456-moex-00105', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於地方自治團體辦理自治事項制定之自治法規，下列敘述何者錯誤？', '["經地方立法機關通過，並由各該行政機關公布者，稱自治條例", "由地方行政機關訂定，並發布或下達者，稱自治規則", "自治條例規定有罰則時，於發布後，應報中央各該主管機關備查", "關於地方自治團體及所營事業機構之組織，應以自治條例定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00106', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政機關依職權撤銷行政處分，下列敘述何者錯誤？', '["授益行政處分之相對人若信賴不值得保護或欠缺信賴表現，則原處分機 關得撤銷該行政處分，且無須給予損失補償", "若撤銷違法行政處分將對公益造成重大危害，則不得將之撤銷", "受益人之信賴值得保護，但信賴利益未大於撤銷所欲維護之公益，則原 處分機關得撤銷該行政處分，但須給予合理之補償", "授益行政處分生效後，尚未確定前，行政機關不得將之撤銷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00107', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列何者屬無持續效力之行政處分？', '["課稅處分", "公務員之任命", "營業許可", "核發月生活補助費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00108', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '甲生向教育部陳情手機被導師保管過久，導師雖隨後發還，但旋以甲經常 遲到、上課睡覺評量德性分數不符申請獎學金資格，下列敘述何者正確？', '["甲生之德性被評量不符獎學金申請資格，甲生得提起行政爭訟", "就甲生之德性成績評量屬於導師之專業判斷，其他教師或機關應絕對尊重", "導師評量德行分數，為事實行為，不影響甲生權益，無違法問題", "甲生使用手機之權益受損屬於學生事務管理事項，不得向教育部陳情"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00109', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列何者為一般處分？', '["警察協助執行違章建築之拆除", "警察對人之管束", "交通號誌", "行政執行分署之催繳通知單"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00110', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政機關與人民締結互負給付義務之行政契約，下列敘述何者正確？', '["契約中無須約定人民給付之特定用途", "契約之締結皆須經上級機關核准", "人民之給付無須有助於行政機關執行其職務", "行政機關收受人民之給付限於契約所載明之特定用途"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00111', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依行政程序法規定，下列何者非屬行政契約無效之情形？', '["受監護宣告之人民獨自簽訂契約", "主管機關與人民就行政罰鍰之金額締結契約", "個案事實與法律關係均由行政機關調查明確後，行政機關仍與人民締結 和解契約，以代替行政處分", "締約雙方均明知，與契約內容相同之行政處分，有得廢止之原因"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00112', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政指導，下列敘述何者正確？', '["行政指導與行政處分均發生法律效果", "我國行政程序法並未明文規定行政指導", "行政指導具有法律上之強制力", "行政指導相對人明確拒絕指導時，行政機關應即停止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00113', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依行政罰法規定，關於罰鍰裁處之審酌加減，下列敘述何者錯誤？', '["裁處罰鍰，得考量受處罰者之資力", "裁處罰鍰，應審酌違反行政法上義務行為應受責難程度、所生影響及因 違反行政法上義務所得之利益", "依行政罰法規定減輕處罰時，裁處之罰鍰原則上不得逾法定罰鍰最高額 之四分之一，亦不得低於法定罰鍰最低額之四分之一", "依行政罰法規定減輕處罰，同時有免除處罰之規定者，裁處之罰鍰原則 上不得逾法定罰鍰最高額之三分之一，亦不得低於法定罰鍰最低額之三 分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00114', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政罰之責任，下列敘述何者正確？', '["行為時因精神障礙或其他心智缺陷，致不能辨識其行為違法或欠缺依其 辨識而行為之能力者，得減輕處罰", "行為時因故意或過失自行招致精神障礙或其他心智缺陷者，不適用減輕 或不予處罰之規定", "未滿 18 歲人之行為，不予處罰；滿 18 歲以上未滿 20 歲人之行為，得 減輕處罰", "不得因不知法規而免除行政處罰責任。但按其情節，僅可減輕其處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
